// SubNode.cpp — Phase 273 W4 (RFC-0047) sub-node: ONE node, TWO callback groups.
//
// This is the core RFC-0047 proof: a single ComponentNode creates two named
// callback groups and creates one timer in each. The entry (generated by
// `nros codegen-system`) seeds bind_group_sched for both groups BEFORE the
// constructor runs, so each timer lands on its resolved sched context:
//
//   bind_group_sched("sub_node", "ctrl",  SC_HIGH) → 10 ms period, high priority
//   bind_group_sched("sub_node", "telem", SC_LOW)  → 100 ms period, low priority
//
// The /ctrl timer fires at the high-tier cadence; /telem at the low-tier cadence.
// The e2e (realtime_subnode_cpp_e2e.rs) asserts ctrl_n >= telem_n * 3 (≥3×).
//
// This is the capability the per-node-name table CANNOT express: two callbacks of
// ONE node scheduled on two different tiers (RFC-0047 motivation §2).

#include "subnode_pkg/SubNode.hpp"

#include <cstdio>
#include <cstring>

namespace subnode_pkg {

// CDR encode of std_msgs/Int32: 4-byte encap header (CDR_LE) + 4-byte int32.
static void encode_int32(uint8_t buf[8], int32_t val) {
    buf[0] = 0x00;
    buf[1] = 0x01;
    buf[2] = 0x00;
    buf[3] = 0x00;
    std::memcpy(buf + 4, &val, 4);
}

void SubNode::on_ctrl() {
    uint8_t buf[8];
    encode_int32(buf, static_cast<int32_t>(ctrl_count_));
    if (ctrl_pub_.publish_raw(buf, sizeof(buf)).ok()) {
        std::printf("[subnode/ctrl] tick=%d\n", ctrl_count_);
    }
    ctrl_count_++;
}

void SubNode::on_telem() {
    uint8_t buf[8];
    encode_int32(buf, static_cast<int32_t>(telem_count_));
    if (telem_pub_.publish_raw(buf, sizeof(buf)).ok()) {
        std::printf("[subnode/telem] tick=%d\n", telem_count_);
    }
    telem_count_++;
}

SubNode::SubNode(::nros::NodeHandle h)
    : ::nros::ComponentNode(h, "sub_node") {
    // Line-buffer stdout so each tick flushes immediately when piped.
    ::setvbuf(stdout, nullptr, _IOLBF, 0);

    // Two callback groups — declared in code (rclcpp shape), tier-assigned in
    // system.toml group_tiers (the package carries NO tier reference — portable).
    auto ctrl_grp  = create_callback_group("ctrl");
    auto telem_grp = create_callback_group("telem");

    ctrl_pub_  = create_publisher<Int32Tag>("/ctrl");
    telem_pub_ = create_publisher<Int32Tag>("/telem");

    // Timer in ctrl group  → bound to high tier (10 ms) via bind_group_sched seed.
    create_timer_in<SubNode, &SubNode::on_ctrl>(ctrl_grp, 10);
    // Timer in telem group → bound to low tier (100 ms) via bind_group_sched seed.
    create_timer_in<SubNode, &SubNode::on_telem>(telem_grp, 100);
}

} // namespace subnode_pkg
